const { ApolloServer } = require('apollo-server-express');
const express = require('express');
const { Pool } = require('pg');

const typeDefs = `
  type Author {
    id: ID!
    name: String!
  }

  type Post {
    id: ID!
    title: String!
    content: String!
    authorId: Int!
    author: Author
  }

  type Query {
    posts: [Post]
  }
`;

const resolvers = {
  Query: {
    async posts() {
      const pool = new Pool({
        user: 'your_username',
        host: 'localhost',
        database: 'your_database',
        password: 'your_password',
        port: 5432,
      });

      try {
        const queryResult = await pool.query(`
          SELECT p.id, p.title, p.content, a.id AS author_id
          FROM posts p
          LEFT JOIN authors a ON p.author_id = a.id
        `);

        const posts = queryResult.rows.map((row) => ({
          id: row.id,
          title: row.title,
          content: row.content,
          authorId: row.author_id,
          author: {
            id: row.author_id,
            name: 'John Doe', // Replace with actual database fetch
          },
        }));

        return posts;
      } finally {
        pool.end();
      }
    },
  },
};

const app = express();

const server = new ApolloServer({ typeDefs, resolvers });

server.applyMiddleware({ app });

app.listen(4000, () => console.log('GraphQL API running on http://localhost:4000/graphql'));